message:
Necesito hacer una migración compleja en producción:
- De: SNS en sa-east-1 (versión legacy, 5 años de deuda técnica)
- A: ECR con arquitectura moderna en sa-east-1
- Sin downtime (SLA 99.95%)
- 292 GB de datos
- 135 millones de usuarios activos

Aquí está el estado actual del Terraform que gestiona el recurso origen:

```hcl
terraform {
  required_version = ">= 1.5"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
  backend "s3" {
    bucket         = "tfstate-producción-3734"
    key            = "ml-inference/terraform.tfstate"
    region         = "sa-east-1"
    encrypt        = true
    dynamodb_table = "tf-lock-producción"
  }
}

provider "aws" {
  region = "sa-east-1"
  default_tags {
    tags = {
      Environment = "producción"
      Service     = "ml-inference"
      ManagedBy   = "terraform"
    }
  }
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "5.1.2"

  name = "ml-inference-producción-vpc"
  cidr = "10.81.0.0/16"

  azs             = ["sa-east-1a", "sa-east-1b", "sa-east-1c"]
  private_subnets = ["10.13.1.0/24", "10.166.2.0/24", "10.61.3.0/24"]
  public_subnets  = ["10.179.101.0/24", "10.78.102.0/24", "10.67.103.0/24"]

  enable_nat_gateway   = true
  single_nat_gateway   = false
  enable_dns_hostnames = true

  tags = {
    "kubernetes.io/cluster/ml-inference-producción" = "shared"
  }
}

module "eks" {
  source  = "terraform-aws-modules/eks/aws"
  version = "20.0.0"

  cluster_name    = "ml-inference-producción"
  cluster_version = "1.31"

  vpc_id     = module.vpc.vpc_id
  subnet_ids = module.vpc.private_subnets

  cluster_endpoint_public_access = true

  eks_managed_node_groups = {
    general = {
      min_size       = 2
      max_size       = 15
      desired_size   = 2
      instance_types = ["m5.2xlarge"]

      labels = {
        role = "general"
      }
    }

    spot = {
      min_size       = 0
      max_size       = 24
      desired_size   = 7
      instance_types = ["m5.xlarge",
                        "m4.2xlarge"]
      capacity_type  = "SPOT"
    }
  }

  cluster_addons = {
    coredns = {
      most_recent = true
    }
    kube-proxy = {
      most_recent = true
    }
    vpc-cni = {
      most_recent = true
    }
    aws-ebs-csi-driver = {
      most_recent              = true
      service_account_role_arn = module.ebs_csi_irsa_role.iam_role_arn
    }
  }
}
```

¿Cuál es el plan de migración paso a paso? ¿Cómo testeo cada fase?
¿Cómo hago el cutover final en menos de 22 minutos?
¿Qué rollback plan tengo si algo falla en el paso final?

