      Environment = "producción"
      Service     = "notification-svc"
      ManagedBy   = "terraform"
    }
  }
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "5.1.2"

  name = "notification-svc-producción-vpc"
  cidr = "10.112.0.0/16"

  azs             = ["us-west-2a", "us-west-2b", "us-west-2c"]
  private_subnets = ["10.39.1.0/24", "10.190.2.0/24", "10.206.3.0/24"]
  public_subnets  = ["10.177.101.0/24", "10.32.102.0/24", "10.37.103.0/24"]

  enable_nat_gateway   = true
  single_nat_gateway   = false
  enable_dns_hostnames = true

  tags = {
    "kubernetes.io/cluster/notification-svc-producción" = "shared"
  }
}

module "eks" {
  source  = "terraform-aws-modules/eks/aws"
  version = "20.0.0"

  cluster_name    = "notification-svc-producción"
  cluster_version = "1.30"

  vpc_id     = module.vpc.vpc_id
  subnet_ids = module.vpc.private_subnets

  cluster_endpoint_public_access = true

  eks_managed_node_groups = {
    general = {
      min_size       = 2
      max_size       = 13
      desired_size   = 3
      instance_types = ["m5.large"]

      labels = {
        role = "general"
      }
    }

    spot = {
      min_size       = 0
      max_size       = 16
      desired_size   = 6
      instance_types = ["m5.2xlarge",
                        "m4.xlarge"]
      capacity_type  = "SPOT"
    }
  }

  cluster_addons = {
    coredns = {
      most_recent = true
    }
    kube-proxy = {
      most_recent = true
    }
    vpc-cni = {
      most_recent = true
    }
    aws-ebs-csi-driver = {
      most_recent              = true
      service_account_role_arn = module.ebs_csi_irsa_role.iam_role_arn
    }
  }
}
